import { PREDATOR_CONFIG } from './predatorConfig';

// ── Types ─────────────────────────────────────────────────────────────────────

export interface TempoChainState {
  /** How many consecutive cards played within tempoChainWindowTicks */
  depth:          number;
  /** Tick of last card play (for window expiry) */
  lastPlayTick:   number;
  /** Cumulative BB bonus earned from chains this round */
  roundChainBonus: number;
}

export interface BattleBudgetState {
  current:          number;
  roundGenerated:   number;
  totalGenerated:   number;
  totalSpent:       number;
  roundCap:         number;
  extractionsFired: number;
  /** Negative BB = forced pause on attacks until cleared */
  bbDebt:           number;
  tempoChain:       TempoChainState;
  /** Rolling ring buffer of per-round generated amounts (last 10 rounds) */
  roundHistory:     number[];
  /** BB spent / BB generated — 0 = hoarding, 1 = perfect spend, >1 = debt */
  efficiency:       number;
}

export const INITIAL_BB_STATE: BattleBudgetState = {
  current:          0,
  roundGenerated:   0,
  totalGenerated:   0,
  totalSpent:       0,
  roundCap:         PREDATOR_CONFIG.bbMaxPerRound,
  extractionsFired: 0,
  bbDebt:           0,
  tempoChain: {
    depth:           0,
    lastPlayTick:    -999,
    roundChainBonus: 0,
  },
  roundHistory: [],
  efficiency:   0,
};

// ── BB Generation ─────────────────────────────────────────────────────────────

export interface BBGenerationInput {
  cardEnergyCost:   number;
  cashflowMonthly:  number;
  /** Current tick (for tempo chain window check) */
  currentTick:      number;
  /** Hater heat from snapshot (amplifies generation) */
  haterHeat?:       number;
}

export interface BBGenerationResult {
  amount:       number;
  chainDepth:   number;
  chainBonus:   number;
  updatedState: BattleBudgetState;
}

/**
 * Generate BB from a card play. This is the SINGLE entry point for all BB generation.
 * predatorCardAdapter.ts must call this instead of computing inline.
 */
export function generateBB(
  input: BBGenerationInput,
  state: BattleBudgetState,
): BBGenerationResult {
  const { cardEnergyCost, cashflowMonthly, currentTick, haterHeat = 0 } = input;

  // ── Base generation ───────────────────────────────────────────────────────
  const heatMult = 1 + haterHeat / 200;
  const baseGen  = Math.round(
    (cardEnergyCost * PREDATOR_CONFIG.bbGenerationRate + cashflowMonthly * 0.5) * heatMult,
  );

  // ── Tempo chain ───────────────────────────────────────────────────────────
  const chain    = state.tempoChain;
  const window   = PREDATOR_CONFIG.tempoChainWindowTicks;
  const withinWindow = currentTick - chain.lastPlayTick <= window;
  const newDepth = withinWindow ? Math.min(chain.depth + 1, PREDATOR_CONFIG.tempoChainMaxDepth) : 1;
  const chainMultiplier = 1 + (newDepth - 1) * PREDATOR_CONFIG.tempoChainBBMultiplierStep;
  const chainBonus = newDepth > 1 ? Math.round(baseGen * (chainMultiplier - 1)) : 0;

  const rawAmount = baseGen + chainBonus;

  // ── Round cap enforcement ─────────────────────────────────────────────────
  const headroom = state.roundCap - state.roundGenerated;
  const amount   = Math.min(rawAmount, Math.max(0, headroom));

  const newTempoChain: TempoChainState = {
    depth:           newDepth,
    lastPlayTick:    currentTick,
    roundChainBonus: chain.roundChainBonus + chainBonus,
  };

  const newTotal    = state.totalGenerated + amount;
  const efficiency  = newTotal > 0
    ? parseFloat(((state.totalSpent) / newTotal).toFixed(3))
    : 0;

  const updatedState: BattleBudgetState = {
    ...state,
    current:        state.current + amount,
    roundGenerated: state.roundGenerated + amount,
    totalGenerated: newTotal,
    tempoChain:     newTempoChain,
    efficiency,
  };

  return { amount, chainDepth: newDepth, chainBonus, updatedState };
}

// ── BB Consumption ────────────────────────────────────────────────────────────

export type BBSpendReason =
  | 'EXTRACTION_FIRE'
  | 'COUNTERPLAY_BLOCK'
  | 'COUNTERPLAY_REFLECT'
  | 'PSYCHE_PRESSURE'
  | 'DECK_CLAIM'
  | 'RIVALRY_AMPLIFIER';

export interface BBSpendResult {
  success:      boolean;
  amountSpent:  number;
  shortfall:    number;
  updatedState: BattleBudgetState;
}

export function spendBB(
  amount: number,
  reason: BBSpendReason,
  state:  BattleBudgetState,
): BBSpendResult {
  if (state.bbDebt > 0) {
    // Debt must be cleared before new extractions — other spends still allowed
    const blockedByDebt =
      reason === 'EXTRACTION_FIRE' ||
      reason === 'PSYCHE_PRESSURE'  ||
      reason === 'DECK_CLAIM';
    if (blockedByDebt) {
      return {
        success:      false,
        amountSpent:  0,
        shortfall:    amount,
        updatedState: state,
      };
    }
  }

  if (state.current < amount) {
    const shortfall = amount - state.current;
    return {
      success:      false,
      amountSpent:  0,
      shortfall,
      updatedState: { ...state, bbDebt: state.bbDebt + shortfall },
    };
  }

  const newSpent    = state.totalSpent + amount;
  const newGen      = state.totalGenerated;
  const efficiency  = newGen > 0 ? parseFloat((newSpent / newGen).toFixed(3)) : 0;

  const updatedState: BattleBudgetState = {
    ...state,
    current:          state.current - amount,
    totalSpent:       newSpent,
    efficiency,
    extractionsFired: reason === 'EXTRACTION_FIRE'
      ? state.extractionsFired + 1
      : state.extractionsFired,
  };

  return { success: true, amountSpent: amount, shortfall: 0, updatedState };
}

// ── Round Reset ───────────────────────────────────────────────────────────────

export function resetBBRound(state: BattleBudgetState): BattleBudgetState {
  const roundHistory = [
    ...state.roundHistory,
    state.roundGenerated,
  ].slice(-10);

  const debtForgiven = Math.min(
    state.bbDebt,
    PREDATOR_CONFIG.bbDebtForgivenessPerRound,
  );

  return {
    ...state,
    roundGenerated: 0,
    bbDebt:         Math.max(0, state.bbDebt - debtForgiven),
    roundHistory,
    tempoChain: {
      depth:           0,
      lastPlayTick:    -999,
      roundChainBonus: 0,
    },
  };
}

// ── Derived ───────────────────────────────────────────────────────────────────

export function canFireExtraction(state: BattleBudgetState, extractionCost: number): boolean {
  return state.current >= extractionCost && state.bbDebt === 0;
}

/** 0 = pure hoarding, 1 = balanced, >1 = over-extended (debt) */
export function getBBEfficiency(state: BattleBudgetState): number {
  return state.efficiency;
}

/** Average BB generated per round over history */
export function getAverageRoundBB(state: BattleBudgetState): number {
  if (!state.roundHistory.length) return 0;
  return Math.round(
    state.roundHistory.reduce((a, b) => a + b, 0) / state.roundHistory.length,
  );
}

export function isTempoChainActive(state: BattleBudgetState, currentTick: number): boolean {
  return (
    state.tempoChain.depth > 1 &&
    currentTick - state.tempoChain.lastPlayTick <= PREDATOR_CONFIG.tempoChainWindowTicks
  );
}

export function getTempoChainMultiplier(state: BattleBudgetState, currentTick: number): number {
  if (!isTempoChainActive(state, currentTick)) return 1.0;
  const depth = state.tempoChain.depth;
  return parseFloat(
    (1 + (depth - 1) * PREDATOR_CONFIG.tempoChainBBMultiplierStep).toFixed(3),
  );
}

export function bbPressureRatio(state: BattleBudgetState): number {
  if (state.totalGenerated === 0) return 0;
  return parseFloat((state.totalSpent / state.totalGenerated).toFixed(3));
}

/** Label for BB state for HUD display */
export function bbStateLabel(state: BattleBudgetState): string {
  if (state.bbDebt > 0) return 'IN DEBT';
  if (state.current >= state.roundCap * 0.8) return 'LOADED';
  if (state.current >= state.roundCap * 0.4) return 'READY';
  return 'BUILDING';
}